import { Badge, BadgeProps, Tabs, TabsProps } from 'antd';
import { FC, ReactNode, useMemo, useState } from 'react';
import SptLabelWithNumber from '../SptLabelWithNumber';
import React from 'react';
import './style/index.less';

export enum SptTabBadgeType {
    // 在一行内进行展示
    Inline,
    // 在右上角进行展示
    Corner,
}

export interface SptWithBadgeTabProps {
    key: string;
    label: string | ReactNode;
    children?: ReactNode;
    count?: number;
}

export interface SptTabWithBadgeProps extends TabsProps {
    items?: SptWithBadgeTabProps[];
    badgeType?: SptTabBadgeType;
    badgeProps?: BadgeProps;
}

/**
 * 带Badge的Tab菜单
 */
const SptTabWithBadge: FC<SptTabWithBadgeProps> = ({
    items,
    onChange,
    badgeType = SptTabBadgeType.Inline,
    badgeProps = {},
    ...props
}) => {
    const [current, setCurrent] = useState(props.activeKey ?? props.defaultActiveKey);

    const innerTabs: TabsProps['items'] = useMemo(
        () =>
            items?.map((item) => {
                return {
                    label:
                        badgeType === SptTabBadgeType.Inline ? (
                            <SptLabelWithNumber
                                active={item.key === current}
                                label={item.label}
                                count={item.count ?? 0}
                            />
                        ) : (
                            <Badge
                                count={item.count}
                                offset={[6, -6]}
                                size={props.size === 'small' ? 'small' : 'default'}
                                className="spt-component-tab-with-badge"
                                {...badgeProps}
                            >
                                {item.label}
                            </Badge>
                        ),
                    key: item.key,
                    children: item.children,
                };
            }),
        [items, current],
    );

    return (
        <Tabs
            items={innerTabs}
            onChange={(activeKey) => {
                setCurrent(activeKey);
                onChange?.(activeKey);
            }}
            {...props}
        />
    );
};

export default SptTabWithBadge;
